import { type CSSProperties, type ReactNode, useCallback, useRef, useState } from "react";

interface MagicCardProps {
  children: ReactNode;
  className?: string;
}

/**
 * MagicCard — wraps children in a container that renders a soft radial
 * spotlight tracking the pointer on hover. The spotlight is a
 * pointer-events-none overlay whose position is driven by the --mx / --my
 * CSS custom properties, updated on mouse move.
 *
 * The wrapper adds NO card chrome (border/background) — children keep their
 * own card classes. The overlay renders above the children (z-10) so it stays
 * visible over opaque card backgrounds, and clips to the wrapper's
 * border-radius via rounded-[inherit] (pass the card radius in className).
 *
 * Motion: the spotlight is a static glow (not motion-heavy), so it still
 * appears under prefers-reduced-motion; only the fade transition is
 * suppressed via the motion-reduce:transition-none utility.
 */
export function MagicCard({ children, className }: MagicCardProps) {
  const ref = useRef<HTMLDivElement>(null);
  const [hovered, setHovered] = useState(false);

  const handleMouseMove = useCallback((event: React.MouseEvent<HTMLDivElement>) => {
    const el = ref.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    el.style.setProperty("--mx", `${event.clientX - rect.left}px`);
    el.style.setProperty("--my", `${event.clientY - rect.top}px`);
  }, []);

  const spotlightStyle: CSSProperties = {
    background:
      "radial-gradient(200px circle at var(--mx) var(--my), color-mix(in oklch, var(--color-fd-primary) 14%, transparent), transparent 70%)",
  };

  return (
    <div
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      className={`relative h-full ${className ?? ""}`}
    >
      <div
        aria-hidden
        style={spotlightStyle}
        className={`pointer-events-none absolute inset-0 z-10 rounded-[inherit] transition-opacity duration-[250ms] motion-reduce:transition-none ${
          hovered ? "opacity-100" : "opacity-0"
        }`}
      />
      <div className="relative h-full">{children}</div>
    </div>
  );
}

export default MagicCard;
